INSERT INTO public.blog_posts (
  slug, title, title_ka, excerpt, excerpt_ka, content, content_ka,
  author, category, categories, featured_image_url, is_published,
  read_time_minutes, created_at, updated_at
) VALUES (
  'polograph-legend-of-love',
  $body$პოლოგრაფი - ლეგენდა სიყვარულზე$body$,
  $body$პოლოგრაფი - ლეგენდა სიყვარულზე$body$,
  $body$ადგილი, სადაც ახლა პოლოგრაფი იქმნება — თავისუფლების, სიმტკიცის, სიყვარულის სიმბოლოა.$body$,
  $body$ადგილი, სადაც ახლა პოლოგრაფი იქმნება — თავისუფლების, სიმტკიცის, სიყვარულის სიმბოლოა.$body$,
  $body$<p>ადგილი, სადაც ახლა პოლოგრაფი იქმნება თავისუფლების, სიმტკიცის, სიყვარულის სიმბოლოა. არსებობს დაუწერელი ტრადიცია, რომ წყვილები ამ ამაღლებულ ადგილს ულამაზესი დაისის ან განათებული ქალაქის პანორამული ხედების სანახავად სტუმრობენ. ხშირად, პირველ პაემან სწორედ პოლოგრაფის ტერიტორიაზე გეგმავენ, რაც ამ ბორცვის ისტორიული ლეგენდის განსხვავებული, კეთილი გაგრძელებაა.</p><p>ლეგენდა გვიყვება, რომ ერთხელ ერთ ახალგაზრდა ვაჟს იქვე, შორი-ახლოს აღმართული ციხის უფლისწულის ასული შეუყვარდა. ვაჟი სამეფო წარმომავლობის არ იყო, ამიტომ რჩეულთან მიახლოება და ხმის გაცემაც კი აუკრძალეს. ლეგენდის თანახმად, ვაჟი იმდენ ხანს იდგა და გაჰყურებდა ციხესიმაგრეს, სანამ მარად შეყვარებულ მთად, მყარი, ურყევი სიყვარულის სიმბოლოდ არ იქცა.</p><p>მეორე ლეგენდის თანახმად, თავისუფლების მოყვარულ ფერად ქარს და მტკიცე, ურყევ ოქროსფერ სერს ერთმანეთი შეუყვარდათ. ყველაფერი კი თბილისთან ახლოს, დედაქალაქიდან სულ რამდენიმე წუთის სავალზე დაიწყო. თურმე, ოდესღაც ქვემო ქართლის ველებზე მოუსვენარი, ცელქი და უმისამართო ქარი დაძრწოდა. ის ძლიერი, ხმაურიანი და თავისუფალი, მაგრამ ძალიან მარტოსული იყო. სადაც კი ჩაივლიდა, ყველაფერი იდრიკებოდა და გაურბოდა — ხეები ტოტებს ხრიდნენ, ყვავილები, კი მიწას ეკვროდნენ.</p><p>ერთხელ, როდესაც ქარმა მწვანე ველს გადაუქროლა, წინ მტკიცე, მზისსხივისფერი სერი დაინახა. ქარმა იფიქრა, მასაც მოხრიდა ან შეაშინებდა, მაგრამ სერი არც კი შეტოკდა. მყარმა, ამაყმა და ურყევმა თავისი კალთები გაუშვირა და ქარს ჩაეხუტა.</p><p>მხოლოდ ამ ბორცვა შეძლო ქარის „მოთვინიერება“, ამიტომ არის ეს მაღლობი მყარი ფუძისა და შიგანი თავისუფლების ერთობლიობა.</p><p>სხვათა შორის, როდესაც ზაფხულის ცხელ დღეებში სუფთა სიო ქალაქების დაბლობს ჩამოუქროლებს, ადამიანები შვებით და მადლიერებით დღესაც ამბობენ - „მთამ სტუმარი ქარს გააცნო“</p><p>ჰოდა,  როდესაც ბორცვზე ამოსულთ სუფთა ჰაერი და სიო თავისუფლების ჟრუანტელს მოგგვრით, გახსოვდეთ რომ „ამ მთის რჩეული ხართ და მან ქარს გაგაცნოთ“.</p>$body$,
  $body$<p>ადგილი, სადაც ახლა პოლოგრაფი იქმნება თავისუფლების, სიმტკიცის, სიყვარულის სიმბოლოა. არსებობს დაუწერელი ტრადიცია, რომ წყვილები ამ ამაღლებულ ადგილს ულამაზესი დაისის ან განათებული ქალაქის პანორამული ხედების სანახავად სტუმრობენ. ხშირად, პირველ პაემან სწორედ პოლოგრაფის ტერიტორიაზე გეგმავენ, რაც ამ ბორცვის ისტორიული ლეგენდის განსხვავებული, კეთილი გაგრძელებაა.</p><p>ლეგენდა გვიყვება, რომ ერთხელ ერთ ახალგაზრდა ვაჟს იქვე, შორი-ახლოს აღმართული ციხის უფლისწულის ასული შეუყვარდა. ვაჟი სამეფო წარმომავლობის არ იყო, ამიტომ რჩეულთან მიახლოება და ხმის გაცემაც კი აუკრძალეს. ლეგენდის თანახმად, ვაჟი იმდენ ხანს იდგა და გაჰყურებდა ციხესიმაგრეს, სანამ მარად შეყვარებულ მთად, მყარი, ურყევი სიყვარულის სიმბოლოდ არ იქცა.</p><p>მეორე ლეგენდის თანახმად, თავისუფლების მოყვარულ ფერად ქარს და მტკიცე, ურყევ ოქროსფერ სერს ერთმანეთი შეუყვარდათ. ყველაფერი კი თბილისთან ახლოს, დედაქალაქიდან სულ რამდენიმე წუთის სავალზე დაიწყო. თურმე, ოდესღაც ქვემო ქართლის ველებზე მოუსვენარი, ცელქი და უმისამართო ქარი დაძრწოდა. ის ძლიერი, ხმაურიანი და თავისუფალი, მაგრამ ძალიან მარტოსული იყო. სადაც კი ჩაივლიდა, ყველაფერი იდრიკებოდა და გაურბოდა — ხეები ტოტებს ხრიდნენ, ყვავილები, კი მიწას ეკვროდნენ.</p><p>ერთხელ, როდესაც ქარმა მწვანე ველს გადაუქროლა, წინ მტკიცე, მზისსხივისფერი სერი დაინახა. ქარმა იფიქრა, მასაც მოხრიდა ან შეაშინებდა, მაგრამ სერი არც კი შეტოკდა. მყარმა, ამაყმა და ურყევმა თავისი კალთები გაუშვირა და ქარს ჩაეხუტა.</p><p>მხოლოდ ამ ბორცვა შეძლო ქარის „მოთვინიერება“, ამიტომ არის ეს მაღლობი მყარი ფუძისა და შიგანი თავისუფლების ერთობლიობა.</p><p>სხვათა შორის, როდესაც ზაფხულის ცხელ დღეებში სუფთა სიო ქალაქების დაბლობს ჩამოუქროლებს, ადამიანები შვებით და მადლიერებით დღესაც ამბობენ - „მთამ სტუმარი ქარს გააცნო“</p><p>ჰოდა,  როდესაც ბორცვზე ამოსულთ სუფთა ჰაერი და სიო თავისუფლების ჟრუანტელს მოგგვრით, გახსოვდეთ რომ „ამ მთის რჩეული ხართ და მან ქარს გაგაცნოთ“.</p>$body$,
  'Polograph',
  'polograph',
  '{polograph}'::text[],
  '/renders/polograph-aerial-1.jpg',
  true,
  4,
  '2026-05-06 10:00:00+00',
  '2026-05-06 10:00:00+00'
)
ON CONFLICT (slug) DO NOTHING;

INSERT INTO public.blog_posts (
  slug, title, title_ka, excerpt, excerpt_ka, content, content_ka,
  author, category, categories, featured_image_url, is_published,
  read_time_minutes, created_at, updated_at
) VALUES (
  'equestrianism-tradition-in-polograph',
  $body$ცხენოსნობა - მეტი ვიდრე სპორტი$body$,
  $body$ცხენოსნობა - მეტი ვიდრე სპორტი$body$,
  $body$ისტორიიდან თანამედროვეობამდე. ცხენოსნობის აღორძინებული ტრადიცია პოლოგრაფში.$body$,
  $body$ისტორიიდან თანამედროვეობამდე. ცხენოსნობის აღორძინებული ტრადიცია პოლოგრაფში.$body$,
  $body$<p>საქართველო, საცხენოსნო სპორტის მიმართულებით მრავალსაუკუნოვანი, მდიდარი ტრადიციით გამოირჩევა. საქართველოს ტერიტორიაზე ჯერ კიდევ ძვ.წ. II-I ათასწლეულის ხანის ბრინჯაოს ლაგამები და აღვირებია აღმოჩენილი. ანტიკურ სამყაროში, როგორც გამორჩეულად სწრაფი და გამძლე, სწორედ კოლხური ცხენის ჯიშები იყო ცნობილი.</p><p>ქართული ცხენოსნობის ისტორიაში ერთ-ერთი ყველაზე გამორჩეული და საამაყო ისტორია XIX საუკუნის ბოლოსა და XX-ის დასაწყისში გურული ცხენოსნების წარმატებას უკავშირდება.</p><p>1892 წელს, როდესაც აშშ -ში სახელმწიფოს დაარსებიდან მეასე წლისთავი აღინიშნებოდა, უამრავ სხვადასხვა ღონისძიებასთან ერთად, ცხენზე ჯირითი ყველაზე პოპულარული სანახაობა იყო. მით უმეტეს, რომ სახელგანთქმული ცხენოსნები მსოფლიოს სხვადასხვა ქვეყნიდან ჩამოდიოდნენ და წარმოდგენებს მართავდნენ. მათ შორის გურული მხედრების 10 კაციანი ჯგუფი, სახელად „ჩოხაგრძელაც“ იღებდა მონაწილეობას.</p><p>„ჩოხაგრძელას“ ევრო-ამერიკული ტურნე 4 წელიწადს გაგრძელდა. გზად, მხედრული ოსტატობით, ჯირითით, ცეკვითა და სიმღერით მათ იტალიელი და ფრანგი მაყურებლების მოხიბვლა შეძლეს. ტრიუმფალური იყო აშშ-ში მოღვაწეობაც.</p><p>შემდეგი წარმატება აშშ-ს აღმოჩენის 400 წლისთავისადმი მიძღვნილ ღონისძიებას უკავშირდება. აღსანიშნავია, რომ ამ ღონისძიებაზე მამაკაც მხედრებთან ერთად ქალი მხედრებიც მონაწილეობდნენ.</p><p>„ბუფალოს ცნობილი შოუ“, რომელსაც უილიამ ქოუდმა 1883 წელს ჩაუყარა საფუძველი ქართველი ცხენოსნების წარმატების კიდევ ერთი ასპარეზი გახდა. შოუს ყოველ ჯერზე 10 – 12 ათასი ადამიანი მაინც ესწრებოდა, აქ სხვადასხვა ქვეყნის წარმომადგენლები, ეროვნულ კოსტუმებში მაყურებელს თავიანთი ქვეყნის ტრადიციებს წარმოუდგენდნენ.</p><p>ქართველები „ბუფალო შოუს“, 1893 წელს ინგლისში მოგზაურობის დროს შემოუერთდნენ. ამ წელს შოუს უპრეცედენტოდ დიდი რაოდენობა, 6 მილიონზე მეტი ადამიანი დაესწრო. ეს იყო ყველაზე წარმატებული სანახაობა შოუს ისტორიაში. ქართველი ცხენოსნების გამოსვლა ამერიკული წარმოდგენების უმნიშვნელოვანესი ნაწილი გახდა, რომელშიც ქათველები 30 წლის განმავლობაში იღებდნენ მონაწილეობას.</p><p>აღსანიშნავია ქართული ცხენოსნობის გავლენაც კოვბოების საცხენოსნო ხელოვნებაზე. მოგვიანებით „თავზეხელაღებული“ ჯირითი და ჰაერში ტრიალი კოვბოების საცხენოსნო ილეთებშიც აისახა.</p><p>ქართველმა მხედრებმა სახელი იმდენად გაითქვეს, რომ ისინი დედოფალმა ვიქტორიამ სასახლეში მიიწვია და საჩუქარი გადასცა, ინგლისის პრესამ კი მათზე უამრავი სტატია და მადლობის წერილი გამოაქვეყნა.</p>$body$,
  $body$<p>საქართველო, საცხენოსნო სპორტის მიმართულებით მრავალსაუკუნოვანი, მდიდარი ტრადიციით გამოირჩევა. საქართველოს ტერიტორიაზე ჯერ კიდევ ძვ.წ. II-I ათასწლეულის ხანის ბრინჯაოს ლაგამები და აღვირებია აღმოჩენილი. ანტიკურ სამყაროში, როგორც გამორჩეულად სწრაფი და გამძლე, სწორედ კოლხური ცხენის ჯიშები იყო ცნობილი.</p><p>ქართული ცხენოსნობის ისტორიაში ერთ-ერთი ყველაზე გამორჩეული და საამაყო ისტორია XIX საუკუნის ბოლოსა და XX-ის დასაწყისში გურული ცხენოსნების წარმატებას უკავშირდება.</p><p>1892 წელს, როდესაც აშშ -ში სახელმწიფოს დაარსებიდან მეასე წლისთავი აღინიშნებოდა, უამრავ სხვადასხვა ღონისძიებასთან ერთად, ცხენზე ჯირითი ყველაზე პოპულარული სანახაობა იყო. მით უმეტეს, რომ სახელგანთქმული ცხენოსნები მსოფლიოს სხვადასხვა ქვეყნიდან ჩამოდიოდნენ და წარმოდგენებს მართავდნენ. მათ შორის გურული მხედრების 10 კაციანი ჯგუფი, სახელად „ჩოხაგრძელაც“ იღებდა მონაწილეობას.</p><p>„ჩოხაგრძელას“ ევრო-ამერიკული ტურნე 4 წელიწადს გაგრძელდა. გზად, მხედრული ოსტატობით, ჯირითით, ცეკვითა და სიმღერით მათ იტალიელი და ფრანგი მაყურებლების მოხიბვლა შეძლეს. ტრიუმფალური იყო აშშ-ში მოღვაწეობაც.</p><p>შემდეგი წარმატება აშშ-ს აღმოჩენის 400 წლისთავისადმი მიძღვნილ ღონისძიებას უკავშირდება. აღსანიშნავია, რომ ამ ღონისძიებაზე მამაკაც მხედრებთან ერთად ქალი მხედრებიც მონაწილეობდნენ.</p><p>„ბუფალოს ცნობილი შოუ“, რომელსაც უილიამ ქოუდმა 1883 წელს ჩაუყარა საფუძველი ქართველი ცხენოსნების წარმატების კიდევ ერთი ასპარეზი გახდა. შოუს ყოველ ჯერზე 10 – 12 ათასი ადამიანი მაინც ესწრებოდა, აქ სხვადასხვა ქვეყნის წარმომადგენლები, ეროვნულ კოსტუმებში მაყურებელს თავიანთი ქვეყნის ტრადიციებს წარმოუდგენდნენ.</p><p>ქართველები „ბუფალო შოუს“, 1893 წელს ინგლისში მოგზაურობის დროს შემოუერთდნენ. ამ წელს შოუს უპრეცედენტოდ დიდი რაოდენობა, 6 მილიონზე მეტი ადამიანი დაესწრო. ეს იყო ყველაზე წარმატებული სანახაობა შოუს ისტორიაში. ქართველი ცხენოსნების გამოსვლა ამერიკული წარმოდგენების უმნიშვნელოვანესი ნაწილი გახდა, რომელშიც ქათველები 30 წლის განმავლობაში იღებდნენ მონაწილეობას.</p><p>აღსანიშნავია ქართული ცხენოსნობის გავლენაც კოვბოების საცხენოსნო ხელოვნებაზე. მოგვიანებით „თავზეხელაღებული“ ჯირითი და ჰაერში ტრიალი კოვბოების საცხენოსნო ილეთებშიც აისახა.</p><p>ქართველმა მხედრებმა სახელი იმდენად გაითქვეს, რომ ისინი დედოფალმა ვიქტორიამ სასახლეში მიიწვია და საჩუქარი გადასცა, ინგლისის პრესამ კი მათზე უამრავი სტატია და მადლობის წერილი გამოაქვეყნა.</p>$body$,
